cd(recent_prices)\n387\t        \n388\t        prev_prices = prices[:-(i+1)]\n389\t        macd_prev, signal_prev, _ = calculate_macd(prev_prices)\n390\t        \n391\t        if macd_curr and signal_curr and macd_prev and signal_prev:\n392\t            if macd_prev < signal_prev and macd_curr > signal_curr:\n393\t                return True\n394\t    \n395\t    return False\n396\t\n397\t# 第一步：获取创业板股票列表\n398\tprint(\"\\n第一步：获取创业板股票列表...\")\n399\ttry:\n400\t    stock_info = ak.stock_info_a_code_name()\n401\t    gem_stocks = stock_info[stock_info['code'].str.startswith('300')].copy()\n402\t    print(f\"创业板股票总数: {len(gem_stocks)}\")\n403\texcept Exception as e:\n404\t    print(f\"获取股票列表失败: {e}\")\n405\t    # 使用模拟数据\n406\t    gem_stocks = pd.DataFrame({\n407\t        'code': [f'30{i:04d}' for i in range(1, 201)],\n408\t        'name': [f'创业板{i}' for i in range(1, 201)]\n409\t    })\n410\t    print(f\"使用模拟数据: {len(gem_stocks)}只股票\")\n411\t\n412\t# 分类行业\n413\tgem_stocks['sector'] = gem_stocks['name'].apply(classify_sector)\n414\tgem_stocks = gem_stocks[gem_stocks['sector'].notna()].copy()\n415\tprint(f\"分类到6大行业的股票数: {len(gem_stocks)}\")\n416\tprint(\"\\n行业分布:\")\n417\tprint(gem_stocks['sector'].value_counts())\n418\t\n419\t# 第二步：计算各行业近20日等权平均涨幅\n420\tprint(f\"\\n第二步：计算各行业近{LOOKBACK_DAYS}日等权平均涨幅...\")\n421\tsector_returns = {}\n422\tstock_data = {}\n423\t\n424\tfor sector in SECTOR_KEYWORDS.keys():\n425\t    sector_stocks = gem_stocks[gem_stocks['sector'] == sector]['code'].tolist()\n426\t    if not sector_stocks:\n427\t        continue\n428\t    \n429\t    returns = []\n430\t    for code in sector_stocks[:50]:  # 限制每个行业最多50只股票加速\n431\t        try:\n432\t            # 获取历史数据\n433\t            df = ak.stock_zh_a_hist(symbol=code, period=\"daily\", \n434\t                                   start_date=(datetime.strptime(END_DATE, \"%Y%m%d\") - timedelta(days=100)).strftime(\"%Y%m%d\"),\n435\t                                   end_date=END_DATE, adjust=\"qfq\")\n436\t         