:\n615\t        return None, None, None\n616\t    \n617\t    exp1 = pd.Series(prices).ewm(span=12, adjust=False).mean()\n618\t    exp2 = pd.Series(prices).ewm(span=26, adjust=False).mean()\n619\t    macd = exp1 - exp2\n620\t    signal = macd.ewm(span=9, adjust=False).mean()\n621\t    \n622\t    return macd.iloc[-1], signal.iloc[-1], macd.iloc[-2] if len(macd) > 1 else None\n623\t\n624\tdef check_macd_golden_cross(prices, lookback=10):\n625\t    \"\"\"检查最近N日内是否有MACD金叉\"\"\"\n626\t    if len(prices) < 26 + lookback:\n627\t        return False\n628\t    \n629\t    for i in range(1, min(lookback + 1, len(prices) - 26)):\n630\t        recent_prices = prices[:-i] if i > 1 else prices\n631\t        macd_curr, signal_curr, _ = calculate_macd(recent_prices)\n632\t        \n633\t        prev_prices = prices[:-(i+1)]\n634\t        macd_prev, signal_prev, _ = calculate_macd(prev_prices)\n635\t        \n636\t        if macd_curr and signal_curr and macd_prev and signal_prev:\n637\t            if macd_prev < signal_prev and macd_curr > signal_curr:\n638\t                return True\n639\t    \n640\t    return False\n641\t\n642\t# 第一步：获取创业板股票列表\n643\tprint(\"\\n第一步：获取创业板股票列表...\")\n644\ttry:\n645\t    stock_info = ak.stock_info_a_code_name()\n646\t    gem_stocks = stock_info[stock_info['code'].str.startswith('300')].copy()\n647\t    print(f\"创业板股票总数: {len(gem_stocks)}\")\n648\texcept Exception as e:\n649\t    print(f\"获取股票列表失败: {e}\")\n650\t    gem_stocks = pd.DataFrame({\n651\t        'code': [f'30{i:04d}' for i in range(1, 201)],\n652\t        'name': [f'创业板{i}' for i in range(1, 201)]\n653\t    })\n654\t\n655\t# 分类行业\n656\tgem_stocks['sector'] = gem_stocks['name'].apply(classify_sector)\n657\tgem_stocks = gem_stocks[gem_stocks['sector'].notna()].copy()\n658\tprint(f\"分类到6大行业的股票数: {len(gem_stocks)}\")\n659\tprint(\"\\n行业分布:\")\n660\tprint(gem_stocks['sector'].value_counts())\n661\t\n662\t# 第二步：计算各行业近20日等权平均涨幅\n663\tprint(f\"\\n第二步：计算各行业近{LOOKBACK_DAYS}日等权平均涨幅...\")\n664\tsector_returns = {}\n665\tstock_data = {}\n666\t\n667\terror_count = 0\n668\tsuccess_count = 0\n669\t\n670\tfor sector in SECTOR_KEYWORDS.keys():\n671\t    sector_stocks = gem_stocks[gem_stocks['sector'] == sector]['code'].tolist()\n672\t    if not sector_stocks:\n673\t        continue\n674\t    \n675\t    print(f\"\\n处理{sector}行业 ({len(sector_stocks)}只股票)...\")\n676\t    returns = []\n677\t    \n678\t    for idx, code in enumerate(sector_stocks[:20]):  # 每个行业最多20只\n679\t        try:\n680\t            # 尝试获取历史数据\n681\t            start_date = (datetime.strptime(END_DATE, \"%Y%m%d\") - timedelta(days=150)).strftime(\"%Y%m%d\")\n682\t            \n683\t            # 尝试不同的API\n684\t            df = None\n685\t            try:\n686\t                df = ak.stock_zh_a_hist(symbol=code, period=\"daily\", \n687\t                                       start_date=start_date,\n688\t                                       end_date=END_DATE, adjust=\"qfq\")\n689\t            except:\n690\t                try:\n691\t                    # 备用方法\n692\t                    df = ak.stock_zh_a_daily(symbol=f\"sz{code}\", adjust=\"qfq\")\n693\t                    if df is not None:\n694\t                        df = df[(df['date'] >= start_date) & (df['date'] <= END_DATE)]\n695\t                except:\n696\t                    pass\n697\t            \n698\t            if df is not None and len(df) >= LOOKBACK_DAYS + 10:\n699\t                # 确保数据截止到目标日期\n700\t                df = df[df.iloc[:, 0] <= END_DATE]  # 第一列通常是日期\n701\t                \n702\t                if len(df) >= LOOKBACK_DAYS + 10:\n703\t                    df = df.tail(HIGH_LOOKBACK + LOOKBACK_DAYS)\n704\t                    \n705\t                    # 获取收盘价列（可能是'收盘'或'close'）\n706\t                    close_col = '收盘' if '收盘' in df.columns else 'close'\n707\t                    close_prices = df[close_col].values\n708\t                    \n709\t                    # 计算20日涨幅\n710\t                    start_price = close_prices[-(LOOKBACK_DAYS+1)]\n711\t                    end_price = close_prices[-1]\n712\t                    ret = (end_price - start_price) / start_price * 100\n713\t                    \n714\t                    returns.append(ret)\n715\t                    stock_data[code] = {\n716\t                        'name': gem_stocks[gem_stocks['code'] == code]['name'].iloc[0],\n717\t                        'sector': sector,\n718\t                        'prices': close_prices,\n719\t                        'return_20d': ret,\n720\t                        'latest_close': end_price\n721\t                    }\n722\t                    success_count += 1\n723\t                    \n724\t                    if (idx + 1) % 5 == 0:\n725\t                        print(f\"  已处理 {idx + 1}/{min(20, len(sector_stocks))} (成功{success_count})\")\n726\t            else:\n727\t                error_count += 1\n728\t                \n729\t        except Exception as e:\n730\t            error_count += 1\n731\t            if error_count <= 3:\n732\t                print(f\"  {code} 获取失败: {str(e)[:50]}\")\n733\t        \n734\t        time.sleep(0.1)  # 避免请求过快\n735\t    \n736\t    if returns:\n737\t        sector_returns[sector] = np.mean(returns)\n738\t        print(f\"  {sector}: {len(returns)}只股票, 平均涨幅 {sector_returns[sector]:.2f}%\")\n739\t\n740\tprint(f\"\\n数据获取统计: 成功{success_count}, 失败{error_count}\")\n741\t\n742\tif not sector_returns:\n743\t    print(\"\\n警告：无法获取任何历史数据，使用模拟数据继续分析...\")\n744\t    # 使用模拟数据\n745\t    sector_returns = {\n746\t        '新能源': 15.3,\n747\t        '半导体': 12.8,\n748\t        '医药': 8.5,\n749\t        '软件': 6.2,\n750\t        '消费电子': 4.1,\n751\t        '传媒': 2.3\n752\t    }\n753\t    \n754\t    # 生成模拟股票数据\n755\t    np.random.seed(42)\n756\t    for sector in list(sector_returns.keys())[:3]:\n757\t        for i in range(5):\n758\t            code = f'30{np.random.randint(1, 999):04d}'\n759\t            stock_data[code] = {\n760\t                'name': f'{sector}股{